};

const ThreatMap: React.FC = () => {
  const [threats, setThreats] = useState<ThreatEvent[]>(MOCK_THREATS);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      const sources = ['لندن', 'موسكو', 'نيويورك', 'باريس', 'الرياض', 'روسيا', 'الولايات المتحدة', 'الصين'];
      const targets = ['دبي', 'سنغافورة', 'سول', 'بكين', 'السعودية', 'ألمانيا'];

      const source = sources[Math.floor(Math.random() * sources.length)];
      const target = targets[Math.floor(Math.random() * targets.length)];

      const newThreat: ThreatEvent = {
        id: Math.random().toString(36).substr(2, 9),
        source,
        target,
        type: ['DDoS', 'Malware', 'SQLi', 'Brute Force'][Math.floor(Math.random() * 4)],
        severity: (['low', 'medium', 'high', 'critical'] as const)[Math.floor(Math.random() * 4)],
        timestamp: new Date().toLocaleTimeString()
      };

      setThreats(prev => [newThreat, ...prev.slice(0, 14)]);
      animateAttack(newThreat);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  const animateAttack = (threat: ThreatEvent) => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    const width = 800;
    const height = 450;

    const projection = d3.geoMercator()
      .scale(120)
      .translate([width / 2, height / 1.5]);

    const srcCoords = COORDINATES[threat.source] || [0, 0];
    const dstCoords = COORDINATES[threat.target] || [0, 0];

    const p1 = projection(srcCoords as [number, number])!;
    const p2 = projection(dstCoords as [number, number])!;

    // رسم القوس
    const lineData = [p1, [(p1[0] + p2[0]) / 2, (p1[1] + p2[1]) / 2 - 50], p2];
    const lineGenerator = d3.line().curve(d3.curveBasis);

    const path = svg.append('path')
      .attr('d', lineGenerator(lineData as any))
      .attr('fill', 'none')
      .attr('stroke', threat.severity === 'critical' ? '#ef4444' : '#06b6d4')
      .attr('stroke-width', 2)
      .attr('stroke-dasharray', '1000 1000')
      .attr('stroke-dashoffset', 1000)
      .attr('opacity', 0.8);

    path.transition()
      .duration(1500)
      .attr('stroke-dashoffset', 0)
      .on('end', () => {
        // نبضة عند الوصول للهدف
        svg.append('circle')
          .attr('cx', p2[0])
          .attr('cy', p2[1])
          .attr('r', 2)
          .attr('fill', '#06b6d4')
          .attr('opacity', 1)
          .transition()
          .duration(1000)
          .attr('r', 20)
          .attr('opacity', 0)
          .remove();

        path.transition()
          .duration(500)
          .attr('opacity', 0)
          .remove();
      });
  };

  return (
    <div id="threats" className="py-24 bg-slate-900/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-6">
          <div className="text-right">
            <h2 className="text-3xl font-black text-white mb-2">رصد <span className="text-cyan-400">التهديدات الحية</span></h2>
