          </div>
          <div className="flex gap-4">
            <div className="flex items-center gap-2 px-4 py-2 bg-green-500/10 border border-green-500/20 text-green-500 text-xs font-bold rounded-sm">
              <Activity className="w-4 h-4 animate-pulse" />
              الأنظمة: نشطة
            </div>
            <div className="flex items-center gap-2 px-4 py-2 bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 text-xs font-bold rounded-sm">
              <Zap className="w-4 h-4" />
              معدل الرصد: عالي
            </div>
          </div>
        </div>

        <div className="grid lg:grid-cols-4 gap-8">
          <div className="lg:col-span-3 relative aspect-[16/9] bg-slate-950 rounded-lg border border-slate-800 overflow-hidden shadow-2xl">
            {/* خلفية الخريطة */}
            <div className="absolute inset-0 opacity-20 pointer-events-none cyber-grid"></div>

            {/* SVG الخريطة والهجمات */}
            <svg 
              ref={svgRef}
              viewBox="0 0 800 450" 
              className="absolute inset-0 w-full h-full"
            >
              {/* رسم خريطة مبسطة كخلفية */}
              <rect width="800" height="450" fill="transparent" />
              <g className="world-map opacity-30">
                {/* تمثيل تخطيطي للقارات */}
                <path d="M150,150 Q200,100 250,150 T350,150" fill="none" stroke="#1e293b" strokeWidth="2" />
                <circle cx="200" cy="180" r="100" fill="none" stroke="#1e293b" strokeWidth="1" strokeDasharray="5,5" />
                <circle cx="500" cy="220" r="150" fill="none" stroke="#1e293b" strokeWidth="1" strokeDasharray="5,5" />
