            <div className="absolute top-4 left-4 flex items-center gap-2 px-3 py-1 bg-slate-900/80 backdrop-blur-md border border-slate-800 rounded text-[10px] text-slate-400 font-mono">
              <div className="w-2 h-2 bg-red-500 rounded-full animate-ping"></div>
