            </div>

            <div className="absolute bottom-4 right-4 text-[10px] text-slate-600 font-mono">
              LAT: 24.7136 | LONG: 46.6753 | VECTOR: TCP/IP
            </div>
          </div>

          <div className="bg-slate-950 rounded-lg border border-slate-800 flex flex-col h-full shadow-2xl">
            <div className="p-4 border-b border-slate-800 bg-slate-900/50 flex items-center justify-between">
