interface LiveAlert {
  id: string;
  type: string;
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM';
  target: string;
  vector: string;
  timestamp: string;
}

const COUNTRIES = [
  'عرض عالمي',
  'المملكة العربية السعودية',
  'إسرائيل',
  'الولايات المتحدة',
  'روسيا',
