              >
                {COUNTRIES.map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* HUD UI */}
        <div className="grid lg:grid-cols-4 gap-1 border border-cyan-500/10 bg-cyan-500/5 rounded-sm overflow-hidden">

          {/* Sidebar Feed */}
