import React, { useState, useEffect, useRef } from 'react';
import { Maximize2, Minimize2, Shield } from 'lucide-react';

interface Attack {
  id: number;
  startX: number;
  startY: number;
  endX: number;
  endY: number;
}

const ThreatMap: React.FC = () => {
  const [attacks, setAttacks] = useState<Attack[]>([]);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const mapRef = useRef<HTMLDivElement>(null);

  // توليد هجمات عشوائية بخطوط سيان
  useEffect(() => {
    const interval = setInterval(() => {
      const newAttack: Attack = {
        id: Date.now(),
        startX: Math.random() * 100,
        startY: Math.random() * 100,
        endX: Math.random() * 100,
        endY: Math.random() * 100,
      };
      setAttacks((prev) => [...prev.slice(-15), newAttack]);
    }, 800);
    return () => clearInterval(interval);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      mapRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  return (
    <div id="threats" className="py-12 bg-slate-950">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* الحاوية الرئيسية للخريطة */}
        <div 
          ref={mapRef}
          className={`relative bg-black border-2 border-cyan-500/30 rounded-lg overflow-hidden transition-all duration-500 shadow-[0_0_50px_rgba(6,182,212,0.1)] ${
            isFullscreen ? 'h-screen w-screen rounded-none border-0' : 'h-[600px] w-full'
          }`}
        >
          {/* خلفية الخريطة (نقاط شبكية رقمية) */}
          <div className="absolute inset-0 opacity-20 pointer-events-none cyber-grid"></div>

          {/* اسم المطور - Abbas Habib */}
          <div className="absolute top-6 right-6 z-20 flex items-center gap-3">
            <div className="flex flex-col items-end">
              <span className="text-[10px] text-cyan-500/50 font-bold tracking-[0.3em] uppercase">Security Lead</span>
              <span className="text-xl font-black text-white glow-text tracking-tighter mono">Abbas Habib</span>
            </div>
            <div className="w-10 h-10 border border-cyan-500/50 rounded flex items-center justify-center bg-cyan-500/10">
              <Shield className="w-6 h-6 text-cyan-400" />
            </div>
          </div>

          {/* زر ملء الشاشة */}
          <button 
            onClick={toggleFullscreen}
            className="absolute bottom-6 left-6 z-20 p-3 bg-slate-900/80 border border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-white transition-all rounded-md backdrop-blur-md"
            title={isFullscreen ? "Exit Fullscreen" : "Enter Fullscreen"}
          >
