import React, { useState, useEffect, useRef } from 'react';
import { Maximize2, Minimize2, Shield, MousePointer2, ZoomIn, ZoomOut, RotateCcw } from 'lucide-react';
import * as d3 from 'd3';

interface Attack {
  id: string;
  source: [number, number];
  target: [number, number];
  progress: number;
}

const ThreatMap: React.FC = () => {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const mapRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const [attacks, setAttacks] = useState<Attack[]>([]);
  const gRef = useRef<SVGGElement>(null);

  // إحداثيات تقريبية لمدن كبرى لزيادة الواقعية
  const majorCities: [number, number][] = [
    [0, 51], // London
    [-74, 40], // NY
    [116, 39], // Beijing
    [39, 21], // Mecca/Saudi
    [37, 55], // Moscow
    [139, 35], // Tokyo
    [151, -33], // Sydney
    [-46, -23], // Sao Paulo
    [18, -33], // Cape Town
    [34, 32], // Tel Aviv
    [55, 25], // Dubai
  ];

  useEffect(() => {
    if (!svgRef.current) return;

    const width = 1000;
    const height = 600;
    const svg = d3.select(svgRef.current);
    const g = d3.select(gRef.current);

    // إعداد الإسقاط الجغرافي (مسطح)
    const projection = d3.geoEquirectangular()
      .scale(160)
      .translate([width / 2, height / 2]);

    const path = d3.geoPath().projection(projection);

    // تحميل بيانات الخريطة
    d3.json('https://raw.githubusercontent.com/holtzy/D3-graph-gallery/master/DATA/world.geojson').then((data: any) => {
      g.selectAll('path')
        .data(data.features)
        .enter()
        .append('path')
        .attr('d', path as any)
        .attr('fill', '#0f172a')
        .attr('stroke', '#22d3ee22')
        .attr('stroke-width', 0.5)
        .on('mouseover', function() {
          d3.select(this).attr('fill', '#1e293b').attr('stroke', '#22d3ee44');
        })
        .on('mouseout', function() {
          d3.select(this).attr('fill', '#0f172a').attr('stroke', '#22d3ee22');
        });
    });

    // إضافة خاصية التكبير والتصغير
    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([1, 8])
      .on('zoom', (event) => {
        g.attr('transform', event.transform);
      });

    svg.call(zoom);

    // وظيفة إضافة هجمة جديدة
    const addAttack = () => {
      const source = majorCities[Math.floor(Math.random() * majorCities.length)];
      let target = majorCities[Math.floor(Math.random() * majorCities.length)];
      while (target === source) {
        target = majorCities[Math.floor(Math.random() * majorCities.length)];
      }

      const id = Math.random().toString(36).substring(7);
      const newAttack: Attack = { id, source, target, progress: 0 };

      setAttacks(prev => [...prev.slice(-20), newAttack]);

      // رسم القوس المتحرك
      const [x0, y0] = projection(source)!;
      const [x1, y1] = projection(target)!;

      const midX = (x0 + x1) / 2;
      const midY = Math.min(y0, y1) - 50;

      const lineContainer = g.append('g').attr('class', `attack-${id}`);

      const attackPath = lineContainer.append('path')
        .attr('d', `M${x0},${y0} Q${midX},${midY} ${x1},${y1}`)
        .attr('fill', 'none')
        .attr('stroke', '#22d3ee')
        .attr('stroke-width', 1.5)
        .attr('stroke-dasharray', '1000')
        .attr('stroke-dashoffset', '1000')
        .style('filter', 'drop-shadow(0 0 5px #22d3ee)');

      attackPath.transition()
        .duration(2000)
        .ease(d3.easeLinear)
        .attr('stroke-dashoffset', 0)
        .on('end', () => {
          lineContainer.append('circle')
            .attr('cx', x1)
            .attr('cy', y1)
            .attr('r', 0)
            .attr('fill', '#22d3ee')
            .transition()
            .duration(500)
            .attr('r', 4)
            .attr('opacity', 0)
            .remove();

          setTimeout(() => {
            lineContainer.transition().duration(1000).style('opacity', 0).remove();
          }, 1000);
        });
    };

    const attackInterval = setInterval(addAttack, 1200);
    return () => {
      clearInterval(attackInterval);
      svg.on('.zoom', null);
    };
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      mapRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  const resetZoom = () => {
    if (svgRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(750)
        .call(d3.zoom<SVGSVGElement, unknown>().transform, d3.zoomIdentity);
    }
  };

  return (
    <div id="threats" className="py-12 bg-slate-950">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* الحاوية الرئيسية للخريطة */}
        <div 
          ref={mapRef}
          className={`relative bg-[#020617] border border-cyan-500/30 rounded-lg overflow-hidden transition-all duration-500 shadow-[0_0_50px_rgba(6,182,212,0.15)] ${
            isFullscreen ? 'h-screen w-screen rounded-none border-0' : 'h-[650px] w-full'
          }`}
        >
          {/* اسم المطور - Abbas Habib */}
          <div className="absolute top-6 right-6 z-30 flex items-center gap-3 bg-slate-950/60 p-3 backdrop-blur-md border border-cyan-500/20 rounded-sm">
            <div className="flex flex-col items-end">
              <span className="text-[9px] text-cyan-500/70 font-bold tracking-[0.4em] uppercase mono">Cyber Architect</span>
              <span className="text-xl font-black text-white glow-text tracking-tighter mono">Abbas Habib</span>
            </div>
            <div className="w-10 h-10 border border-cyan-500/50 rounded flex items-center justify-center bg-cyan-500/10 shadow-[0_0_10px_rgba(6,182,212,0.3)]">
              <Shield className="w-6 h-6 text-cyan-400" />
            </div>
          </div>

          {/* عناصر التحكم في الخريطة */}
          <div className="absolute bottom-6 right-6 z-30 flex flex-col gap-2">
            <button 
              onClick={toggleFullscreen}
              className="p-3 bg-slate-900/80 border border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-white transition-all rounded-sm backdrop-blur-md shadow-lg"
              title="Fullscreen"
            >
              {isFullscreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
            </button>
            <button 
              onClick={resetZoom}
              className="p-3 bg-slate-900/80 border border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-white transition-all rounded-sm backdrop-blur-md shadow-lg"
              title="Reset View"
            >
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>

          <div className="absolute bottom-6 left-6 z-30 pointer-events-none">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-cyan-500/10 border border-cyan-500/30 backdrop-blur-sm rounded-sm">
               <div className="w-2 h-2 bg-cyan-500 rounded-full animate-pulse"></div>
               <span className="text-[10px] text-cyan-400 font-bold uppercase tracking-widest mono">Live Node Surveillance</span>
            </div>
          </div>

          {/* الخريطة التفاعلية */}
          <svg 
            ref={svgRef} 
            viewBox="0 0 1000 600" 
            preserveAspectRatio="xMidYMid slice"
            className="w-full h-full cursor-grab active:cursor-grabbing outline-none"
          >
            <rect width="1000" height="600" fill="transparent" />
            <g ref={gRef}></g>
          </svg>

          {/* تأثير المسح الراداري العمودي */}
          <div className="absolute inset-0 pointer-events-none opacity-30">
            <div className="h-1 bg-cyan-500/20 w-full absolute animate-radar-scan"></div>
          </div>

          {/* زوايا الديكور */}
          <div className="absolute top-0 left-0 w-12 h-12 border-t-2 border-l-2 border-cyan-500/40 pointer-events-none"></div>
          <div className="absolute top-0 right-0 w-12 h-12 border-t-2 border-r-2 border-cyan-500/40 pointer-events-none"></div>
          <div className="absolute bottom-0 left-0 w-12 h-12 border-b-2 border-l-2 border-cyan-500/40 pointer-events-none"></div>
          <div className="absolute bottom-0 right-0 w-12 h-12 border-b-2 border-r-2 border-cyan-500/40 pointer-events-none"></div>
        </div>

        {/* تذييل معلوماتي */}
        <div className="mt-4 flex flex-col sm:flex-row justify-between items-center text-[9px] text-cyan-800 font-bold uppercase tracking-[0.2em] px-2 gap-2">
          <div className="flex items-center gap-4">
            <span>Satellite ID: SHIELD-01</span>
            <span>Uptime: 99.99%</span>
          </div>
          <div className="hidden sm:block">
            <span>Encrypted Stream: ACTIVE (AES-256-GCM)</span>
          </div>
          <div>
            <span>By Abbas Habib</span>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes radar-scan {
          from { top: -5%; }
          to { top: 105%; }
        }
        .animate-radar-scan {
          animation: radar-scan 8s linear infinite;
        }
