import React, { useState, useEffect, useRef } from 'react';
import { Maximize2, Minimize2, Shield, RotateCcw, AlertTriangle, Crosshair, Terminal, Activity, Zap } from 'lucide-react';
import * as d3 from 'd3';

interface Attack {
  id: string;
  sourceName: string;
  targetName: string;
  type: string;
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM';
  timestamp: string;
}

const CITIES: { name: string; nameAr: string; coords: [number, number] }[] = [
  { name: 'London', nameAr: 'لندن', coords: [0, 51] },
  { name: 'New York', nameAr: 'نيويورك', coords: [-74, 40] },
  { name: 'Beijing', nameAr: 'بكين', coords: [116, 39] },
  { name: 'Riyadh', nameAr: 'الرياض', coords: [46.7, 24.7] },
  { name: 'Moscow', nameAr: 'موسكو', coords: [37, 55] },
  { name: 'Tokyo', nameAr: 'طوكيو', coords: [139, 35] },
  { name: 'Sydney', nameAr: 'سيدني', coords: [151, -33] },
  { name: 'Dubai', nameAr: 'دبي', coords: [55, 25] },
  { name: 'Berlin', nameAr: 'برلين', coords: [13, 52] },
  { name: 'Paris', nameAr: 'باريس', coords: [2, 48] },
  { name: 'San Francisco', nameAr: 'سان فرانسيسكو', coords: [-122, 37] },
  { name: 'Cairo', nameAr: 'القاهرة', coords: [31.2, 30] },
];

const ATTACK_TYPES = [
  'هجوم DDoS مكثف',
  'حقن برمجيات فدية',
  'ثغرة يوم صفر (Zero-Day)',
  'محاولة اختراق قواعد بيانات',
  'هجوم استغلال فيض الذاكرة',
  'تسلل عبر بروتوكول SSH'
];

const ThreatMap: React.FC = () => {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [liveLog, setLiveLog] = useState<Attack[]>([]);
  const [activeAlert, setActiveAlert] = useState<Attack | null>(null);
  const [hoveredCountry, setHoveredCountry] = useState<{name: string, x: number, y: number} | null>(null);

  const mapRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const gRef = useRef<SVGGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const width = 1000;
    const height = 600;
    const svg = d3.select(svgRef.current);
    const g = d3.select(gRef.current);

    const projection = d3.geoEquirectangular()
      .scale(160)
      .translate([width / 2, height / 2]);

    const path = d3.geoPath().projection(projection);

    // تحميل الخريطة مع إضافة أحداث الماوس
    d3.json('https://raw.githubusercontent.com/holtzy/D3-graph-gallery/master/DATA/world.geojson').then((data: any) => {
      g.selectAll('path')
        .data(data.features)
        .enter()
        .append('path')
        .attr('d', path as any)
        .attr('fill', '#0f172a')
        .attr('stroke', '#22d3ee15')
        .attr('stroke-width', 0.5)
        .attr('class', 'country-path cursor-crosshair transition-all duration-300')
        .on('mouseover', function(event, d: any) {
          d3.select(this).attr('fill', '#1e293b').attr('stroke', '#22d3ee88');
          setHoveredCountry({
            name: d.properties.name,
            x: event.clientX,
            y: event.clientY
          });
        })
        .on('mousemove', function(event) {
          setHoveredCountry(prev => prev ? { ...prev, x: event.clientX, y: event.clientY } : null);
        })
        .on('mouseout', function() {
          d3.select(this).attr('fill', '#0f172a').attr('stroke', '#22d3ee15');
          setHoveredCountry(null);
        });
    });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([1, 15])
      .on('zoom', (event) => {
        g.attr('transform', event.transform);
      });

    svg.call(zoom);

    const triggerAttack = () => {
      const source = CITIES[Math.floor(Math.random() * CITIES.length)];
      let target = CITIES[Math.floor(Math.random() * CITIES.length)];
      while (target.name === source.name) {
        target = CITIES[Math.floor(Math.random() * CITIES.length)];
      }

      const id = Math.random().toString(36).substring(7);
      const isCritical = Math.random() > 0.85;
      const severity = isCritical ? 'CRITICAL' : (Math.random() > 0.5 ? 'HIGH' : 'MEDIUM');
      const type = ATTACK_TYPES[Math.floor(Math.random() * ATTACK_TYPES.length)];

      const newAttack: Attack = {
        id,
        sourceName: source.nameAr,
        targetName: target.nameAr,
        type,
        severity,
        timestamp: new Date().toLocaleTimeString('ar-EG'),
      };

      setLiveLog(prev => [newAttack, ...prev].slice(0, 8));

      if (isCritical) {
        setActiveAlert(newAttack);
        setTimeout(() => setActiveAlert(null), 5000);
      }

      // رسم القوس
      const [x0, y0] = projection(source.coords)!;
      const [x1, y1] = projection(target.coords)!;
      const midX = (x0 + x1) / 2;
      const midY = Math.min(y0, y1) - (Math.abs(x1 - x0) * 0.25);

      const attackG = g.append('g').attr('class', `attack-group-${id}`);

      const arc = attackG.append('path')
        .attr('d', `M${x0},${y0} Q${midX},${midY} ${x1},${y1}`)
        .attr('fill', 'none')
        .attr('stroke', isCritical ? '#ef4444' : '#22d3ee')
        .attr('stroke-width', isCritical ? 2 : 1.2)
        .attr('stroke-dasharray', '1000')
        .attr('stroke-dashoffset', '1000')
        .style('filter', `drop-shadow(0 0 8px ${isCritical ? '#ef4444' : '#22d3ee'})`);

      arc.transition()
        .duration(1800)
        .ease(d3.easeQuadInOut)
        .attr('stroke-dashoffset', 0)
        .on('end', () => {
          const impact = attackG.append('circle')
            .attr('cx', x1)
            .attr('cy', y1)
            .attr('r', 0)
            .attr('fill', isCritical ? '#ef4444' : '#22d3ee')
            .attr('opacity', 0.9);

          impact.transition()
            .duration(1000)
            .attr('r', isCritical ? 25 : 12)
            .attr('opacity', 0)
            .remove();

          const label = attackG.append('text')
            .attr('x', x1)
            .attr('y', y1 - 15)
            .attr('text-anchor', 'middle')
            .attr('fill', isCritical ? '#f87171' : '#67e8f9')
            .attr('font-size', '9px')
            .attr('font-weight', 'bold')
            .attr('class', 'mono')
            .text(`${target.nameAr} : ${type}`);

          label.transition()
            .duration(2500)
            .style('opacity', 0)
            .remove();

          setTimeout(() => {
            attackG.transition().duration(1000).style('opacity', 0).remove();
          }, 3000);
        });
    };

    const interval = setInterval(triggerAttack, 1200);
    return () => {
      clearInterval(interval);
      svg.on('.zoom', null);
    };
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      mapRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  const resetZoom = () => {
    if (svgRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(750)
        .call(d3.zoom<SVGSVGElement, unknown>().transform, d3.zoomIdentity);
    }
  };

  return (
    <div id="threats" className="py-12 bg-slate-950 relative">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* Tooltip المخصص لأسماء الدول */}
        {hoveredCountry && (
          <div 
            className="fixed z-[200] pointer-events-none bg-slate-900/95 border border-cyan-500/40 px-3 py-1.5 rounded-sm shadow-2xl backdrop-blur-md flex items-center gap-2"
            style={{ left: hoveredCountry.x + 15, top: hoveredCountry.y + 15 }}
          >
            <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-pulse"></div>
            <span className="text-white font-bold text-xs uppercase tracking-widest mono">{hoveredCountry.name}</span>
          </div>
        )}

        {/* تنبيه حرج */}
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[150] transition-all duration-500 transform ${activeAlert ? 'translate-y-0 opacity-100' : '-translate-y-20 opacity-0 pointer-events-none'}`}>
          <div className="bg-red-600/90 backdrop-blur-xl border border-red-400 text-white px-8 py-5 rounded shadow-[0_0_50px_rgba(239,68,68,0.6)] flex items-center gap-5 min-w-[360px]">
            <Zap className="w-8 h-8 animate-bounce text-yellow-300" />
            <div>
              <div className="text-[10px] font-black uppercase tracking-[0.3em] opacity-80">تنبيه: اختراق أمني حرج</div>
              <div className="font-bold text-xl leading-tight">{activeAlert?.type}</div>
              <div className="text-xs opacity-90 mt-1">الهدف: {activeAlert?.targetName} | المصدر: {activeAlert?.sourceName}</div>
            </div>
          </div>
        </div>

        <div 
          ref={mapRef}
          className={`relative bg-[#010409] border border-cyan-500/20 rounded-lg overflow-hidden transition-all duration-500 shadow-[0_0_70px_rgba(6,182,212,0.15)] ${
            isFullscreen ? 'h-screen w-screen rounded-none border-0' : 'h-[680px] w-full'
          }`}
        >
          {/* اسم المطور - Abbas Habib */}
          <div className="absolute top-6 right-6 z-30 flex items-center gap-4 bg-slate-950/85 p-4 backdrop-blur-xl border border-cyan-500/30 rounded-sm shadow-xl">
            <div className="flex flex-col items-end">
              <span className="text-[9px] text-cyan-500/70 font-bold tracking-[0.5em] uppercase mono">Cyber Architect</span>
              <span className="text-2xl font-black text-white glow-text tracking-tighter mono">Abbas Habib</span>
            </div>
            <div className="w-12 h-12 border-2 border-cyan-500/40 rounded flex items-center justify-center bg-cyan-500/10 group">
              <Shield className="w-7 h-7 text-cyan-400 group-hover:scale-110 transition-transform" />
            </div>
          </div>

          {/* سجل الاستخبارات الحي */}
          <div className="absolute top-6 left-6 z-30 w-72 hidden lg:block">
            <div className="bg-slate-950/85 backdrop-blur-xl border border-cyan-500/25 rounded-sm overflow-hidden shadow-2xl">
              <div className="bg-cyan-500/15 p-3 border-b border-cyan-500/25 flex items-center justify-between">
                <span className="text-[11px] font-black text-cyan-300 uppercase flex items-center gap-2 tracking-widest">
                  <Terminal className="w-4 h-4" />
                  رصد التهديدات
                </span>
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-red-500 rounded-full animate-ping"></div>
                  <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full"></div>
                </div>
              </div>
              <div className="p-3 space-y-3 h-56 overflow-y-hidden">
                {liveLog.map((log) => (
                  <div key={log.id} className="text-[10px] mono border-r-2 border-cyan-500/40 pr-3 py-1.5 animate-fade-in bg-cyan-500/5">
                    <div className="flex justify-between items-center text-cyan-600 mb-1">
                      <span>{log.timestamp}</span>
                      <span className={log.severity === 'CRITICAL' ? 'text-red-500 font-bold' : 'text-cyan-400'}>[{log.severity}]</span>
                    </div>
                    <div className="text-slate-300 truncate font-bold leading-tight">
                      {log.sourceName} <span className="text-cyan-500">>></span> {log.targetName}
                    </div>
                    <div className="text-[9px] text-slate-500 italic mt-0.5">{log.type}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* أزرار التحكم */}
          <div className="absolute bottom-8 right-8 z-30 flex flex-col gap-3">
            <button 
              onClick={toggleFullscreen}
              className="p-4 bg-slate-900/90 border border-cyan-500/40 text-cyan-400 hover:bg-cyan-500 hover:text-white transition-all rounded-sm backdrop-blur-xl shadow-2xl group"
              title="ملء الشاشة"
            >
              {isFullscreen ? <Minimize2 className="w-6 h-6" /> : <Maximize2 className="w-6 h-6 group-hover:scale-110" />}
            </button>
            <button 
              onClick={resetZoom}
              className="p-4 bg-slate-900/90 border border-cyan-500/40 text-cyan-400 hover:bg-cyan-500 hover:text-white transition-all rounded-sm backdrop-blur-xl shadow-2xl group"
              title="إعادة الضبط"
            >
              <RotateCcw className="w-6 h-6 group-hover:rotate-180 transition-transform duration-500" />
            </button>
          </div>

          {/* حالة النظام */}
          <div className="absolute bottom-8 left-8 z-30 pointer-events-none flex gap-5">
            <div className="flex items-center gap-3 px-4 py-2 bg-slate-950/90 border border-cyan-500/25 backdrop-blur-xl rounded-sm">
               <Crosshair className="w-4 h-4 text-cyan-400" />
               <span className="text-[10px] text-cyan-400 font-bold uppercase tracking-widest mono">الحالة: نشط</span>
            </div>
            <div className="flex items-center gap-3 px-4 py-2 bg-slate-950/90 border border-cyan-500/25 backdrop-blur-xl rounded-sm">
               <Activity className="w-4 h-4 text-cyan-400" />
               <span className="text-[10px] text-cyan-400 font-bold uppercase tracking-widest mono">الاتصال: 100%</span>
            </div>
          </div>

          {/* الخريطة SVG */}
          <svg 
            ref={svgRef} 
            viewBox="0 0 1000 600" 
            preserveAspectRatio="xMidYMid slice"
            className="w-full h-full cursor-crosshair active:cursor-grabbing outline-none"
          >
            <rect width="1000" height="600" fill="transparent" />
            <g ref={gRef}></g>
          </svg>

          {/* تأثير المسح الراداري */}
          <div className="absolute inset-0 pointer-events-none opacity-25">
            <div className="h-[2px] bg-cyan-500/40 w-full absolute animate-radar-scan shadow-[0_0_20px_rgba(34,211,238,0.7)]"></div>
          </div>

          {/* حدود الديكور التقنية */}
          <div className="absolute top-0 left-0 w-20 h-20 border-t-2 border-l-2 border-cyan-500/20 pointer-events-none"></div>
          <div className="absolute top-0 right-0 w-20 h-20 border-t-2 border-r-2 border-cyan-500/20 pointer-events-none"></div>
          <div className="absolute bottom-0 left-0 w-20 h-20 border-b-2 border-l-2 border-cyan-500/20 pointer-events-none"></div>
          <div className="absolute bottom-0 right-0 w-20 h-20 border-b-2 border-r-2 border-cyan-500/20 pointer-events-none"></div>
        </div>

        {/* تذييل الخريطة */}
        <div className="mt-5 flex flex-col sm:flex-row justify-between items-center text-[10px] text-cyan-900 font-black uppercase tracking-[0.4em] px-3 gap-3">
          <div className="flex items-center gap-8">
            <span className="flex items-center gap-2"><Activity className="w-3 h-3" /> ضغط الخادم: 12.8%</span>
            <span>وقت الاستجابة: 18ms</span>
          </div>
          <div className="flex items-center gap-2 bg-cyan-950/20 px-4 py-1 rounded-full border border-cyan-900/20">
            <Shield className="w-3 h-3" />
