            <div>
              <div className="text-[10px] font-black uppercase tracking-[0.2em] opacity-80">تنبيه فوري: خرق سيبراني</div>
              <div className="font-bold text-lg leading-tight">{activeAlert?.type}</div>
              <div className="text-xs opacity-90 mt-1">الهدف: {activeAlert?.targetName}</div>
            </div>
          </div>
        </div>

        {/* الحاوية الرئيسية للهيكلة الجانبية */}
        <div className="flex flex-col lg:flex-row gap-6 h-[750px]">

          {/* قسم رصد التهديدات (يسار) */}
          <div className="w-full lg:w-80 h-full flex flex-col bg-slate-900/40 border border-slate-800 rounded-lg overflow-hidden backdrop-blur-sm">
            <div className="bg-slate-900/80 p-4 border-b border-slate-800 flex items-center justify-between">
              <h3 className="text-sm font-black text-cyan-400 flex items-center gap-2 uppercase tracking-tighter">
                <Terminal className="w-4 h-4" />
