              <div className="flex items-center gap-1.5">
                <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] text-slate-500 font-bold uppercase mono">Live</span>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
              {liveLog.length === 0 && (
                <div className="h-full flex flex-center items-center justify-center opacity-20 italic text-xs">
                  بانتظار تدفق البيانات...
                </div>
              )}
              {liveLog.map((log) => (
                <div key={log.id} className="group relative border-r-4 pr-3 py-2 bg-slate-900/60 rounded-sm animate-fade-in hover:bg-slate-800/80 transition-colors" style={{ borderRightColor: log.color }}>
                  <div className="flex justify-between items-center mb-1 text-[10px]">
                    <span className="text-slate-500 mono">{log.timestamp}</span>
                    <span className="font-black" style={{ color: log.color }}>[{log.severity}]</span>
