                  <div className="text-[10px] text-slate-400 mt-1 flex items-center gap-1">
                    <span className="opacity-50">{log.sourceName}</span>
                    <span className="text-cyan-500/50">→</span>
                    <span>{log.targetName}</span>
                  </div>
                </div>
              ))}
            </div>

            <div className="p-3 bg-slate-950/80 border-t border-slate-800 flex items-center justify-between">
              <div className="flex gap-2">
                <div className="w-2 h-2 rounded-full bg-cyan-500" title="DDoS"></div>
                <div className="w-2 h-2 rounded-full bg-purple-500" title="Ransomware"></div>
                <div className="w-2 h-2 rounded-full bg-red-500" title="Critical"></div>
              </div>
              <span className="text-[9px] text-slate-600 font-bold mono">THREAT_LEVEL: STABLE</span>
            </div>
          </div>

          {/* قسم الخريطة (يمين) */}
          <div 
            ref={mapRef}
            className={`flex-1 relative bg-[#010409] border border-cyan-500/20 rounded-lg overflow-hidden transition-all duration-500 shadow-2xl ${
              isFullscreen ? 'fixed inset-0 z-[200] rounded-none' : ''
            }`}
          >
            {/* HUD Overlay - Developer Name */}
            <div className="absolute top-6 right-6 z-30 flex items-center gap-4 bg-slate-950/80 p-3 backdrop-blur-md border border-cyan-500/20 rounded-sm">
              <div className="flex flex-col items-end">
                <span className="text-[8px] text-cyan-500/60 font-bold tracking-[0.5em] uppercase mono">Lead Architect</span>
                <span className="text-xl font-black text-white glow-text tracking-tighter mono">Abbas Habib</span>
              </div>
              <div className="w-10 h-10 border border-cyan-500/30 rounded flex items-center justify-center bg-cyan-500/5 shadow-[0_0_10px_rgba(6,182,212,0.2)]">
