          <div className="flex items-center gap-2 bg-cyan-950/20 px-4 py-1.5 rounded border border-cyan-900/20">
            <Shield className="w-3 h-3" />
            <span>Developed by Abbas Habib</span>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes radar-scan {
          from { top: -2%; }
          to { top: 102%; }
        }
        .animate-radar-scan {
          animation: radar-scan 14s linear infinite;
        }
        @keyframes fade-in {
          from { opacity: 0; transform: translateX(10px); }
          to { opacity: 1; transform: translateX(0); }
