import React, { useState, useEffect, useRef } from 'react';
import { Maximize2, Minimize2, Shield, RotateCcw, AlertTriangle, Crosshair, Terminal, Activity, Zap, Radio } from 'lucide-react';
import * as d3 from 'd3';

interface Attack {
  id: string;
  sourceName: string;
  targetName: string;
  type: string;
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM';
  timestamp: string;
  color: string;
}

const CITIES: { name: string; nameAr: string; coords: [number, number] }[] = [
  { name: 'London', nameAr: 'لندن', coords: [0, 51] },
  { name: 'New York', nameAr: 'نيويورك', coords: [-74, 40] },
  { name: 'Beijing', nameAr: 'بكين', coords: [116, 39] },
  { name: 'Riyadh', nameAr: 'الرياض', coords: [46.7, 24.7] },
  { name: 'Moscow', nameAr: 'موسكو', coords: [37, 55] },
  { name: 'Tokyo', nameAr: 'طوكيو', coords: [139, 35] },
  { name: 'Sydney', nameAr: 'سيدني', coords: [151, -33] },
  { name: 'Dubai', nameAr: 'دبي', coords: [55, 25] },
  { name: 'Berlin', nameAr: 'برلين', coords: [13, 52] },
  { name: 'Paris', nameAr: 'باريس', coords: [2, 48] },
  { name: 'San Francisco', nameAr: 'سان فرانسيسكو', coords: [-122, 37] },
  { name: 'Cairo', nameAr: 'القاهرة', coords: [31.2, 30] },
];

const ATTACK_CONFIGS = [
  { type: 'هجوم DDoS مكثف', color: '#22d3ee' },
  { type: 'حقن برمجيات فدية', color: '#a855f7' },
  { type: 'ثغرة يوم صفر (Zero-Day)', color: '#ef4444' },
  { type: 'محاولة اختراق SQL', color: '#eab308' },
  { type: 'هجوم القوة الغاشمة', color: '#f97316' },
  { type: 'تسلل عبر الأنفاق', color: '#22c55e' }
];

const ThreatMap: React.FC = () => {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [liveLog, setLiveLog] = useState<Attack[]>([]);
  const [activeAlert, setActiveAlert] = useState<Attack | null>(null);
  const [hoveredCountry, setHoveredCountry] = useState<{name: string, x: number, y: number} | null>(null);

  const mapRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const gRef = useRef<SVGGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const width = 1000;
    const height = 600;
    const svg = d3.select(svgRef.current);
    const g = d3.select(gRef.current);

    const projection = d3.geoEquirectangular()
      .scale(160)
      .translate([width / 2, height / 2]);

    const path = d3.geoPath().projection(projection);

    // تعريف التدرجات اللونية لتأثير المذنب
    const defs = svg.append('defs');
    ATTACK_CONFIGS.forEach((config, i) => {
      const grad = defs.append('linearGradient')
        .attr('id', `grad-${i}`)
        .attr('x1', '0%').attr('y1', '0%')
        .attr('x2', '100%').attr('y2', '0%');
      grad.append('stop').attr('offset', '0%').attr('stop-color', 'transparent');
      grad.append('stop').attr('offset', '100%').attr('stop-color', config.color);
    });

    d3.json('https://raw.githubusercontent.com/holtzy/D3-graph-gallery/master/DATA/world.geojson').then((data: any) => {
      g.selectAll('path')
        .data(data.features)
        .enter()
        .append('path')
        .attr('d', path as any)
        .attr('fill', '#080c14')
        .attr('stroke', '#22d3ee15')
        .attr('stroke-width', 0.5)
        .attr('class', 'country-path cursor-crosshair transition-all duration-300')
        .on('mouseover', function(event, d: any) {
          d3.select(this).attr('fill', '#111827').attr('stroke', '#22d3ee55');
          setHoveredCountry({
            name: d.properties.name,
            x: event.clientX,
            y: event.clientY
          });
        })
        .on('mousemove', function(event) {
          setHoveredCountry(prev => prev ? { ...prev, x: event.clientX, y: event.clientY } : null);
        })
        .on('mouseout', function() {
          d3.select(this).attr('fill', '#080c14').attr('stroke', '#22d3ee15');
          setHoveredCountry(null);
        });

      // إضافة نقاط المدن الرئيسية كنبضات دائمة
      CITIES.forEach(city => {
        const [cx, cy] = projection(city.coords)!;
        const cityGroup = g.append('g').attr('class', 'city-pulse');
        cityGroup.append('circle')
          .attr('cx', cx).attr('cy', cy).attr('r', 2)
          .attr('fill', '#22d3ee').attr('opacity', 0.5);
        cityGroup.append('circle')
          .attr('cx', cx).attr('cy', cy).attr('r', 2)
          .attr('fill', 'none').attr('stroke', '#22d3ee')
          .attr('stroke-width', 0.5)
          .attr('class', 'animate-ping-slow');
      });
    });

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([1, 15])
      .on('zoom', (event) => {
        g.attr('transform', event.transform);
      });

    svg.call(zoom);

    const triggerAttack = () => {
      const source = CITIES[Math.floor(Math.random() * CITIES.length)];
      let target = CITIES[Math.floor(Math.random() * CITIES.length)];
      while (target.name === source.name) {
        target = CITIES[Math.floor(Math.random() * CITIES.length)];
      }

      const id = Math.random().toString(36).substring(7);
      const configIndex = Math.floor(Math.random() * ATTACK_CONFIGS.length);
      const config = ATTACK_CONFIGS[configIndex];
      const severity = config.color === '#ef4444' ? 'CRITICAL' : (Math.random() > 0.6 ? 'HIGH' : 'MEDIUM');

      const newAttack: Attack = {
        id,
        sourceName: source.nameAr,
        targetName: target.nameAr,
        type: config.type,
        severity,
        color: config.color,
        timestamp: new Date().toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      };

      setLiveLog(prev => [newAttack, ...prev].slice(0, 15));

      if (severity === 'CRITICAL') {
        setActiveAlert(newAttack);
        setTimeout(() => setActiveAlert(null), 3000);
      }

      const [x0, y0] = projection(source.coords)!;
      const [x1, y1] = projection(target.coords)!;
      const midX = (x0 + x1) / 2;
      const midY = Math.min(y0, y1) - (Math.abs(x1 - x0) * 0.3);

      const attackG = g.append('g').attr('class', `attack-group-${id}`);

      // رسم الخط الخفي للمسار
      const pathData = `M${x0},${y0} Q${midX},${midY} ${x1},${y1}`;

      // تأثير المذنب (رأس متحرك)
      const comet = attackG.append('circle')
        .attr('r', severity === 'CRITICAL' ? 3 : 2)
        .attr('fill', config.color)
        .style('filter', `drop-shadow(0 0 4px ${config.color})`);

      // حركة المذنب على طول المسار
      const pathNode = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      pathNode.setAttribute('d', pathData);
      const totalLength = pathNode.getTotalLength();

      // رسم المسار كخط باهت جداً
      attackG.append('path')
        .attr('d', pathData)
        .attr('fill', 'none')
        .attr('stroke', config.color)
        .attr('stroke-width', 0.5)
        .attr('opacity', 0.15);

      comet.transition()
        .duration(1200)
        .ease(d3.easeLinear)
        .attrTween('transform', () => {
          return (t) => {
            const point = pathNode.getPointAtLength(t * totalLength);
            return `translate(${point.x},${point.y})`;
          };
        })
        .on('end', () => {
          comet.remove();
          // تأثير الارتطام
          const impact = attackG.append('circle')
            .attr('cx', x1).attr('cy', y1)
            .attr('r', 0)
            .attr('fill', config.color)
            .attr('opacity', 0.8);

          impact.transition()
            .duration(600)
            .attr('r', severity === 'CRITICAL' ? 15 : 8)
            .attr('opacity', 0)
            .remove();

          setTimeout(() => {
            attackG.transition().duration(500).style('opacity', 0).remove();
          }, 1000);
        });
    };

    const interval = setInterval(triggerAttack, 800); // زيادة التردد لجعله "مباشراً" أكثر
    return () => {
      clearInterval(interval);
      svg.on('.zoom', null);
    };
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      mapRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  const resetZoom = () => {
    if (svgRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(750)
        .call(d3.zoom<SVGSVGElement, unknown>().transform, d3.zoomIdentity);
    }
  };

  return (
    <div id="threats" className="py-12 bg-slate-950 relative overflow-hidden">
      {/* توهج خلفي ناعم */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[400px] bg-cyan-500/5 blur-[120px] pointer-events-none"></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">

        {/* Tooltip */}
        {hoveredCountry && (
          <div 
            className="fixed z-[200] pointer-events-none bg-slate-950/90 border border-cyan-500/30 px-2 py-1 rounded-sm shadow-2xl backdrop-blur-md flex items-center gap-2"
            style={{ left: hoveredCountry.x + 12, top: hoveredCountry.y + 12 }}
          >
            <div className="w-1 h-1 bg-cyan-400 rounded-full animate-pulse"></div>
            <span className="text-white font-bold text-[10px] mono uppercase tracking-tighter">{hoveredCountry.name}</span>
          </div>
        )}

        {/* تنبيه حرج */}
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[150] transition-all duration-500 transform ${activeAlert ? 'translate-y-0 opacity-100' : '-translate-y-20 opacity-0 pointer-events-none'}`}>
          <div className="bg-slate-900/95 backdrop-blur-xl border border-red-500/50 text-white px-6 py-3 rounded shadow-[0_0_40px_rgba(239,68,68,0.3)] flex items-center gap-4 min-w-[300px]">
            <div className="relative">
