import React, { useState, useRef, useEffect } from 'react';
import { Send, X, Bot, Cpu } from 'lucide-react';
import { getCyberAdvice } from '../services/geminiService';
import { ChatMessage } from '../types';

const BinaryScatterEffect: React.FC<{ active: boolean }> = ({ active }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (!active || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    let particles: Particle[] = [];
    const fontSize = 14;

    class Particle {
      x: number;
      y: number;
      char: string;
      vy: number;
      vx: number;
      opacity: number;
      state: 'falling' | 'scattering';
      life: number;

      constructor() {
        this.reset();
      }

      reset() {
        this.x = Math.random() * canvas.width;
        this.y = -20 - (Math.random() * 100);
        this.char = Math.random() > 0.5 ? '1' : '0';
        this.vy = 2 + Math.random() * 5;
        this.vx = 0;
        this.opacity = 1;
        this.state = 'falling';
        this.life = 100 + Math.random() * 100;
      }

      update() {
        if (this.state === 'falling') {
          this.y += this.vy;
          if (this.y > canvas.height * 0.4) { // Start scattering mid-way
            this.state = 'scattering';
            this.vx = (Math.random() - 0.5) * 10;
            this.vy = (Math.random() - 0.5) * 10;
          }
        } else {
          this.x += this.vx;
          this.y += this.vy;
          this.opacity -= 0.02;
        }

        if (this.opacity <= 0) {
          this.reset();
        }
      }

      draw() {
        if (!ctx) return;
        ctx.fillStyle = `rgba(6, 182, 212, ${this.opacity * 0.4})`;
        ctx.font = `${fontSize}px JetBrains Mono, monospace`;
        ctx.fillText(this.char, this.x, this.y);
      }
    }

    // Initialize particles
    for (let i = 0; i < 150; i++) {
      particles.push(new Particle());
    }

    let animationId: number;
    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach(p => {
        p.update();
        p.draw();
      });
      animationId = requestAnimationFrame(animate);
    };

    animate();

    return () => cancelAnimationFrame(animationId);
  }, [active]);

  if (!active) return null;

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 pointer-events-none z-[-1] opacity-50"
    />
  );
};

