          </div>
        )}

        {/* تنبيه حرج - نسخة محسنة بصرياً - z-index عالي جداً لضمان الظهور في المقدمة */}
        <div className={`fixed top-28 left-1/2 -translate-x-1/2 z-[1000] transition-all duration-700 transform ${activeAlert ? 'translate-y-0 opacity-100 scale-100' : '-translate-y-48 opacity-0 scale-90 pointer-events-none'}`}>
          <div className="relative group">
