            <div className="absolute -inset-2 bg-red-600/20 blur-3xl rounded-2xl animate-pulse"></div>
            <div className="absolute -inset-0.5 bg-gradient-to-r from-red-600 via-orange-600 to-red-600 opacity-50 blur-sm rounded-xl"></div>

            <div className="relative bg-[#0a0505]/90 backdrop-blur-3xl border border-red-500/50 px-10 py-6 rounded-xl shadow-[0_0_80px_rgba(239,68,68,0.4)] flex items-center gap-8 min-w-[500px] overflow-hidden">

              {/* Scanline / Radar Animation */}
              <div className="absolute inset-0 bg-[linear-gradient(rgba(239,68,68,0)_0%,rgba(239,68,68,0.1)_50%,rgba(239,68,68,0)_100%)] h-12 w-full -translate-y-full animate-radar-scan opacity-40"></div>
              <div className="absolute inset-0 cyber-grid opacity-10"></div>

              <div className="relative shrink-0">
