      {/* Auth Status Banner */}
      {(isAuthenticated || isDemoMode) && (
        <div className="fixed top-24 left-8 z-[60] animate-fade-in pointer-events-none">
          <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border border-cyan-500/30 px-4 py-2 rounded-lg flex items-center gap-3 shadow-2xl shadow-black/10">
