            <div className="text-right">
              <p className="text-[10px] font-black text-slate-900 dark:text-white uppercase tracking-tighter">
                {isDemoMode ? 'وضع العرض (DEMO)' : 'حساب خبير نشط'}
              </p>
              <p className="text-[8px] text-cyan-600 dark:text-cyan-400 font-bold uppercase tracking-widest">Verified Session</p>
            </div>
          </div>
        </div>
