  const selectedCountryRef = useRef<string | null>(null);

  // تحديث ألوان الخريطة
  useEffect(() => {
    selectedCountryRef.current = selectedCountry?.name || null;
    if (gRef.current) {
      d3.select(gRef.current).selectAll('path')
        .transition().duration(300)
        .attr('fill', (d: any) => d.properties.name === selectedCountry?.name ? '#0e3a4d' : '#05070a')
