import React, { useState, useMemo } from 'react';
import { ARTICLES } from '../constants';
import { Calendar, User, ArrowLeft, Search, X, PlusCircle, LayoutGrid } from 'lucide-react';
import { UserRole, Article } from '../types';

interface BlogSectionProps {
  userRole: UserRole;
}

const BlogSection: React.FC<BlogSectionProps> = ({ userRole }) => {
  const [activeCategory, setActiveCategory] = useState<string>('الكل');
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [blogArticles, setBlogArticles] = useState<Article[]>(ARTICLES);
  const [showForm, setShowForm] = useState(false);

  const [newArticle, setNewArticle] = useState<Partial<Article>>({
    title: '',
    excerpt: '',
    category: 'News',
    image: 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b'
  });

  const categories = ['الكل', 'أخبار', 'تعليم', 'تحليل التهديدات', 'الثغرات', 'تقنية'];
  const categoryMap: Record<string, string> = {
    'أخبار': 'News',
    'تعليم': 'Education',
    'تحليل التهديدات': 'Threat Analysis',
    'الثغرات': 'Vulnerabilities',
    'تقنية': 'Tech'
  };

  const filteredArticles = useMemo(() => {
    return blogArticles.filter(article => {
      const matchesCategory = activeCategory === 'الكل' || article.category === categoryMap[activeCategory];
      const matchesSearch = article.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            article.excerpt.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchTerm, blogArticles]);

  const handleAddArticle = (e: React.FormEvent) => {
    e.preventDefault();
    if (userRole !== 'admin') return;

    const article: Article = {
      id: Date.now().toString(),
      title: newArticle.title || 'بدون عنوان',
      excerpt: newArticle.excerpt || 'بدون وصف',
      category: newArticle.category as any,
      date: new Date().toISOString().split('T')[0],
      image: newArticle.image || 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b',
      author: 'مدير المنصة'
    };

    setBlogArticles([article, ...blogArticles]);
    setShowForm(false);
  };

  return (
    <section id="news" className="py-24 bg-slate-950">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        <div className="flex flex-col gap-10 mb-16">
          <div className="flex justify-between items-end flex-row-reverse">
            <div className="text-right">
              <h2 className="text-4xl font-black text-white mb-4">آخر <span className="text-cyan-400 italic">التقارير والتحليلات</span></h2>
              <p className="text-slate-500">المحتوى الإداري المحدث بأحدث التهديدات.</p>
            </div>
            {userRole === 'admin' && (
              <button 
                onClick={() => setShowForm(!showForm)}
                className="flex items-center gap-2 bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-lg font-black transition-all"
              >
                <PlusCircle className="w-5 h-5" />
                نشر تقرير جديد
              </button>
            )}
          </div>

          {showForm && (
            <div className="bg-slate-900 p-8 rounded-2xl border border-red-500/20 animate-slide-up text-right">
              <h3 className="text-white font-black text-xl mb-6">نشر محتوى جديد (Admin Only)</h3>
              <form onSubmit={handleAddArticle} className="grid md:grid-cols-2 gap-6">
                <div className="space-y-4">
                  <input 
                    type="text" 
                    placeholder="عنوان المقال" 
                    onChange={e => setNewArticle({...newArticle, title: e.target.value})}
                    className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-cyan-500 outline-none text-right"
                  />
                  <select 
                    onChange={e => setNewArticle({...newArticle, category: e.target.value as any})}
                    className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-cyan-500 outline-none text-right"
                  >
                    <option value="News">أخبار</option>
                    <option value="Threat Analysis">تحليل تهديدات</option>
                    <option value="Education">تعليم</option>
                  </select>
                </div>
                <div className="space-y-4">
                  <textarea 
                    placeholder="ملخص المقال" 
                    rows={4}
                    onChange={e => setNewArticle({...newArticle, excerpt: e.target.value})}
                    className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-cyan-500 outline-none text-right"
                  />
                  <button type="submit" className="w-full bg-red-600 text-white py-3 rounded-lg font-black">تأكيد النشر العام</button>
                </div>
              </form>
            </div>
          )}

          <div className="flex flex-col lg:flex-row gap-6 items-center justify-between">
            <div className="relative w-full lg:w-96 order-2 lg:order-1">
              <Search className="absolute right-4 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-500" />
              <input
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="ابحث في الأرشيف الإداري..."
                className="w-full bg-slate-900 border border-slate-800 text-white rounded-lg py-3 pr-12 pl-4 focus:border-cyan-500 outline-none text-right"
              />
            </div>

            <div className="flex gap-2 bg-slate-900 p-1 rounded border border-slate-800 overflow-x-auto order-1 lg:order-2">
              {categories.map((cat) => (
                <button 
                  key={cat} 
                  onClick={() => setActiveCategory(cat)}
                  className={`px-6 py-2 rounded-sm text-sm font-bold whitespace-nowrap transition-all ${
                    activeCategory === cat ? 'bg-cyan-600 text-white' : 'text-slate-400 hover:text-white'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredArticles.map((article) => (
            <article key={article.id} className="group bg-slate-900/50 border border-slate-800 rounded-lg overflow-hidden hover:border-cyan-500/50 transition-all transform hover:-translate-y-1">
              <div className="relative h-56">
                <img src={article.image} alt={article.title} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500" />
                <div className="absolute top-4 right-4 bg-slate-950/80 border border-cyan-500/30 px-3 py-1 text-[10px] text-cyan-400 font-black uppercase">
                  {article.category}
                </div>
              </div>
              <div className="p-6 text-right">
                <div className="flex items-center justify-end gap-3 text-[10px] text-slate-500 mb-4 uppercase">
                  <Calendar className="w-3 h-3" /> {article.date} | <User className="w-3 h-3" /> {article.author}
                </div>
                <h3 className="text-xl font-bold text-white mb-4 leading-tight group-hover:text-cyan-400 transition-colors line-clamp-2">{article.title}</h3>
                <p className="text-slate-400 text-sm mb-6 line-clamp-2 leading-relaxed">{article.excerpt}</p>
                <div className="flex justify-start pt-4 border-t border-slate-800/50">
                  <a href="#" className="inline-flex items-center gap-2 text-cyan-400 font-bold text-sm">
                    اقرأ المزيد <ArrowLeft className="w-4 h-4" />
                  </a>
                </div>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default BlogSection;

