  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setShowLoginModal(false);
  };

  const handleLogout = () => {
    setUserRole('guest');
  };

  const renderView = () => {
    switch (currentView) {
      case 'experts':
        return <CommunitySection userRole={userRole} />;
      case 'about':
      case 'contact':
      case 'privacy':
        return <InfoSection type={currentView} />;
      default:
        return (
          <>
            <Hero onNavigate={(view) => setCurrentView(view)} />
            <OperationsHub />
            <ThreatMap />
            <BlogSection userRole={userRole} />
            <StoriesSection /> {/* تمت إعادة القصص هنا */}
          </>
        );
    }
  };

  return (
    <div className="min-h-screen selection:bg-cyan-500 selection:text-white bg-slate-950 transition-colors duration-300 overflow-x-hidden">
      <InteractiveBackground />

      {showLoginModal && (
        <Login onLogin={handleLogin} onClose={() => setShowLoginModal(false)} />
      )}

      {userRole !== 'guest' && (
        <div className="fixed top-24 left-8 z-[60] animate-fade-in pointer-events-none">
          <div className={`bg-slate-900/80 backdrop-blur-xl border px-4 py-2 rounded-lg flex items-center gap-3 shadow-2xl ${
            userRole === 'admin' ? 'border-red-500/40' : 'border-cyan-500/30'
          }`}>
            <div className="relative">
              {userRole === 'admin' ? <UserCog className="w-5 h-5 text-red-500" /> : <UserCheck className="w-5 h-5 text-green-500" />}
              <span className="absolute -top-1 -right-1 w-2 h-2 bg-current rounded-full animate-ping"></span>
            </div>
            <div className="text-right">
              <p className="text-[10px] font-black text-white uppercase tracking-tighter">
                {userRole === 'admin' ? 'صلاحية مدير النظام (ADMIN)' : 'صلاحية خبير تقني'}
              </p>
              <p className={`text-[8px] font-bold uppercase tracking-widest ${userRole === 'admin' ? 'text-red-400' : 'text-cyan-400'}`}>
                {userRole === 'admin' ? 'Root Access Active' : 'Verified Expert Session'}
              </p>
            </div>
          </div>
        </div>
      )}

      <div className="relative z-10">
        <Navbar 
          onOpenLogin={() => setShowLoginModal(true)} 
          isAuthenticated={userRole !== 'guest'} 
          onLogout={handleLogout}
          onNavigate={(view) => setCurrentView(view)}
          currentView={currentView}
        />

        <main className="min-h-[70vh]">
          {renderView()}
        </main>

        <AIChat />
        <Footer onNavigate={(view) => setCurrentView(view)} />
      </div>
    </div>
  );
};

