import InfoSection from './components/InfoSection';
import AIChat from './components/AIChat';
import Footer from './components/Footer';
import Login from './components/Login';
import InteractiveBackground from './components/InteractiveBackground';
import AdminDashboard from './components/AdminDashboard';
import { UserCog, UserCheck, LayoutDashboard } from 'lucide-react';
import { UserRole, Article, Story } from './types';
import { INITIAL_ARTICLES, INITIAL_STORIES } from './constants';

export type AppView = 'home' | 'experts' | 'stories' | 'about' | 'contact' | 'privacy' | 'dashboard';

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>('guest');
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>('home');

  // Dynamic Content Management
  const [articles, setArticles] = useState<Article[]>(INITIAL_ARTICLES);
  const [stories, setStories] = useState<Story[]>(INITIAL_STORIES);

  useEffect(() => {
    document.documentElement.classList.add('dark');
  }, []);

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setShowLoginModal(false);
    if (role === 'admin') {
      setCurrentView('dashboard');
    }
  };

  const handleLogout = () => {
    setUserRole('guest');
    setCurrentView('home');
  };

  const addArticle = (art: Article) => setArticles([art, ...articles]);
  const addStory = (sto: Story) => setStories([sto, ...stories]);
  const deleteArticle = (id: string) => setArticles(articles.filter(a => a.id !== id));
  const deleteStory = (id: string) => setStories(stories.filter(s => s.id !== id));

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return (
          <AdminDashboard 
            articles={articles} 
            stories={stories} 
            onAddArticle={addArticle} 
            onAddStory={addStory} 
            onDeleteArticle={deleteArticle}
            onDeleteStory={deleteStory}
          />
        );
      case 'experts':
        return <CommunitySection userRole={userRole} />;
      case 'about':
      case 'contact':
      case 'privacy':
        return <InfoSection type={currentView} />;
      default:
        return (
          <>
            <Hero onNavigate={(view) => setCurrentView(view)} />
            <OperationsHub />
            <ThreatMap />
            {/* Blog Section updated to use dynamic state */}
            <BlogSection userRole={userRole} articles={articles} />
            <StoriesSection stories={stories} />
          </>
        );
    }
  };

  return (
    <div className="min-h-screen selection:bg-cyan-500 selection:text-white bg-slate-950 transition-colors duration-300 overflow-x-hidden">
      <InteractiveBackground />

      {showLoginModal && (
        <Login onLogin={handleLogin} onClose={() => setShowLoginModal(false)} />
      )}

      {/* Floating Dashboard Action for Admin */}
      {userRole === 'admin' && currentView !== 'dashboard' && (
        <button 
          onClick={() => setCurrentView('dashboard')}
          className="fixed top-24 left-8 z-[100] bg-cyan-600 hover:bg-cyan-500 text-white p-4 rounded-full shadow-2xl transition-all group border border-cyan-400/50"
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="absolute right-full mr-4 top-1/2 -translate-y-1/2 bg-slate-900 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap border border-slate-800">
            لوحة الإدارة
          </span>
        </button>
      )}

      {userRole !== 'guest' && currentView !== 'dashboard' && (
        <div className="fixed top-24 left-8 z-[60] animate-fade-in pointer-events-none">
          <div className={`bg-slate-900/80 backdrop-blur-xl border px-4 py-2 rounded-lg flex items-center gap-3 shadow-2xl ${
            userRole === 'admin' ? 'border-red-500/40' : 'border-cyan-500/30'
          }`}>
            <div className="relative">
              {userRole === 'admin' ? <UserCog className="w-5 h-5 text-red-500" /> : <UserCheck className="w-5 h-5 text-green-500" />}
              <span className="absolute -top-1 -right-1 w-2 h-2 bg-current rounded-full animate-ping"></span>
            </div>
            <div className="text-right">
              <p className="text-[10px] font-black text-white uppercase tracking-tighter">
                {userRole === 'admin' ? 'صلاحية مدير النظام (ADMIN)' : 'صلاحية خبير تقني'}
              </p>
              <p className={`text-[8px] font-bold uppercase tracking-widest ${userRole === 'admin' ? 'text-red-400' : 'text-cyan-400'}`}>
                {userRole === 'admin' ? 'Root Access Active' : 'Verified Expert Session'}
              </p>
            </div>
          </div>
        </div>
      )}

      <div className="relative z-10">
        <Navbar 
          onOpenLogin={() => setShowLoginModal(true)} 
          isAuthenticated={userRole !== 'guest'} 
          onLogout={handleLogout}
          onNavigate={(view) => setCurrentView(view)}
          currentView={currentView}
        />

        <main className="min-h-[70vh]">
          {renderView()}
        </main>

        <AIChat />
        <Footer onNavigate={(view) => setCurrentView(view)} />
      </div>
    </div>
  );
};

export default App;

