import React, { useState, useEffect } from 'react';
import { Shield, Lock, User, Activity, Database, X, Terminal, Key, Smartphone, Fingerprint, RefreshCw } from 'lucide-react';
import { UserRole } from '../types';

interface LoginProps {
  onLogin: (role: UserRole) => void;
  onClose: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onClose }) => {
  const [adminPass, setAdminPass] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [verificationStep, setVerificationStep] = useState(false);
  const [vCode, setVCode] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [generatedCode, setGeneratedCode] = useState('');

  const handleExpertLogin = () => onLogin('expert');

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPass === 'admin123') {
      const code = Math.floor(1000 + Math.random() * 9000).toString();
      setGeneratedCode(code);
      setVerificationStep(true);
    } else {
      alert('شفرة الوصول غير صحيحة. تم تسجيل محاولة الدخول الفاشلة.');
    }
  };

  const handleFinalVerify = (e: React.FormEvent) => {
    e.preventDefault();
    setIsVerifying(true);
    setTimeout(() => {
      if (vCode === generatedCode) {
        onLogin('admin');
      } else {
        alert('رمز التحقق غير صحيح.');
        setIsVerifying(false);
      }
    }, 1500);
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#010409]/95 backdrop-blur-md cursor-pointer" onClick={onClose}></div>

      <div className="relative w-full max-w-lg animate-fade-in">
        <div className="bg-slate-900/80 backdrop-blur-3xl border border-cyan-500/20 rounded-2xl p-8 lg:p-12 shadow-[0_0_100px_rgba(0,0,0,0.8)] relative overflow-hidden">

          <button onClick={onClose} className="absolute top-6 left-6 p-2 text-slate-500 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>

          <div className="text-center mb-10">
            <div className="relative inline-flex mb-6">
              <div className="absolute inset-0 bg-cyan-500/20 blur-2xl rounded-full animate-pulse"></div>
              <div className="relative p-5 bg-slate-950 rounded-2xl border border-cyan-500/20 text-cyan-400">
                <Shield className="w-12 h-12" />
              </div>
            </div>
            <h2 className="text-3xl font-black text-white italic uppercase">بوابة <span className="text-cyan-400">التحقق الأمنية</span></h2>
            {!verificationStep && <p className="text-slate-500 text-xs mt-2 uppercase tracking-widest font-bold">Secure Gateway v4.0.1</p>}
          </div>

          <div className="space-y-6">
            {!showAdminLogin ? (
              <>
                <button 
                  onClick={handleExpertLogin}
                  className="w-full bg-cyan-600 hover:bg-cyan-500 text-white font-black py-4 rounded-lg flex items-center justify-center gap-3 transition-all shadow-lg shadow-cyan-900/20"
                >
                  <Terminal className="w-5 h-5" />
                  دخول الخبراء (عرض الخدمات)
                </button>
                <button 
                  onClick={() => setShowAdminLogin(true)}
                  className="w-full bg-slate-800 hover:bg-slate-700 text-slate-400 font-bold py-4 rounded-lg border border-slate-700 flex items-center justify-center gap-3 transition-all"
                >
                  <Key className="w-5 h-5" />
                  دخول المسؤول (الإدارة)
                </button>
              </>
            ) : !verificationStep ? (
              <form onSubmit={handleAdminAuth} className="space-y-4 animate-slide-up">
                <div className="relative">
                  <Lock className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type="password" 
                    autoFocus
                    value={adminPass}
                    onChange={(e) => setAdminPass(e.target.value)}
                    placeholder="أدخل شفرة الإدارة العليا"
                    className="w-full bg-slate-950/80 border border-slate-800 rounded-lg py-4 pr-12 pl-4 text-white focus:border-cyan-500 focus:outline-none text-right"
                  />
                </div>
                <div className="flex gap-2">
                   <button type="submit" className="flex-1 bg-red-600 hover:bg-red-500 text-white font-black py-4 rounded-lg">التالي: خطوة التحقق</button>
                   <button type="button" onClick={() => setShowAdminLogin(false)} className="px-6 bg-slate-800 text-slate-400 rounded-lg">إلغاء</button>
                </div>
              </form>
            ) : (
              <form onSubmit={handleFinalVerify} className="space-y-6 animate-slide-up text-center">
                <div className="p-6 bg-cyan-500/5 border border-cyan-500/20 rounded-2xl mb-4">
                   {/* Fixed typo: Using correctly imported 'Smartphone' icon component */}
                   <Smartphone className="w-10 h-10 text-cyan-500 mx-auto mb-4" />
                   <p className="text-xs text-slate-400 mb-2 font-bold uppercase tracking-widest">تم إرسال رمز التحقق الآلي</p>
                   <p className="text-xl font-black text-white mono tracking-[0.5em] bg-slate-950 py-2 rounded border border-slate-800">
                     {generatedCode}
                   </p>
                   <p className="text-[9px] text-slate-600 mt-2 italic">(محاكاة لخطوة التحقق الثنائية 2FA)</p>
                </div>

                <input 
                  type="text" 
                  maxLength={4}
                  required
                  autoFocus
                  value={vCode}
                  onChange={(e) => setVCode(e.target.value)}
                  placeholder="أدخل الرمز هنا"
                  className="w-full bg-slate-950 border border-slate-800 rounded-lg py-4 px-4 text-center text-2xl font-black text-cyan-400 focus:border-cyan-500 focus:outline-none mono"
                />

                <button 
                  disabled={isVerifying}
                  type="submit" 
                  className="w-full bg-cyan-600 hover:bg-cyan-500 text-white font-black py-4 rounded-lg flex items-center justify-center gap-3 transition-all disabled:opacity-50"
                >
                  {isVerifying ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Fingerprint className="w-5 h-5" />}
                  {isVerifying ? 'جاري التحقق الرقمي...' : 'تأكيد الهوية والدخول'}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ThreatMap from './components/ThreatMap';
import OperationsHub from './components/OperationsHub';
import StoriesSection from './components/StoriesSection';
import CommunitySection from './components/CommunitySection';
import BlogSection from './components/BlogSection';
import InfoSection from './components/InfoSection';
import AIChat from './components/AIChat';
import Footer from './components/Footer';
import InteractiveBackground from './components/InteractiveBackground';
import AdminDashboard from './components/AdminDashboard';
import { LayoutDashboard, PenTool } from 'lucide-react';
import { UserRole, Article, Story } from './types';
import { INITIAL_ARTICLES, INITIAL_STORIES } from './constants';

export type AppView = 'home' | 'experts' | 'stories' | 'about' | 'contact' | 'privacy' | 'dashboard';

const App: React.FC = () => {
  // تم جعل الدور الافتراضي 'admin' لإتاحة أدوات النشر مباشرة بدون تسجيل دخول
  const [userRole] = useState<UserRole>('admin');
  const [currentView, setCurrentView] = useState<AppView>('home');

  // إدارة المحتوى الديناميكي
  const [articles, setArticles] = useState<Article[]>(INITIAL_ARTICLES);
  const [stories, setStories] = useState<Story[]>(INITIAL_STORIES);

  useEffect(() => {
    document.documentElement.classList.add('dark');
  }, []);

  const addArticle = (art: Article) => setArticles([art, ...articles]);
  const addStory = (sto: Story) => setStories([sto, ...stories]);
  const deleteArticle = (id: string) => setArticles(articles.filter(a => a.id !== id));
  const deleteStory = (id: string) => setStories(stories.filter(s => s.id !== id));

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return (
          <AdminDashboard 
            articles={articles} 
            stories={stories} 
            onAddArticle={addArticle} 
            onAddStory={addStory} 
            onDeleteArticle={deleteArticle}
            onDeleteStory={deleteStory}
          />
        );
      case 'experts':
        return <CommunitySection userRole={userRole} />;
      case 'about':
      case 'contact':
      case 'privacy':
        return <InfoSection type={currentView} />;
      default:
        return (
          <>
            <Hero onNavigate={(view) => setCurrentView(view)} />
            <OperationsHub />
            <ThreatMap />
            <BlogSection userRole={userRole} articles={articles} />
            <StoriesSection stories={stories} />
          </>
        );
    }
  };

  return (
    <div className="min-h-screen selection:bg-cyan-500 selection:text-white bg-slate-950 transition-colors duration-300 overflow-x-hidden">
      <InteractiveBackground />

      {/* زر عائم للوصول السريع للوحة التحكم للنشر */}
      {currentView !== 'dashboard' && (
        <button 
          onClick={() => setCurrentView('dashboard')}
          className="fixed top-24 left-8 z-[100] bg-cyan-600 hover:bg-cyan-500 text-white p-4 rounded-full shadow-2xl transition-all group border border-cyan-400/50 flex items-center gap-2"
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-500 whitespace-nowrap text-xs font-black uppercase tracking-widest pl-0 group-hover:pl-2">
            لوحة النشر
          </span>
        </button>
      )}

      <div className="relative z-10">
        <Navbar 
          onNavigate={(view) => setCurrentView(view)}
          currentView={currentView}
        />

        <main className="min-h-[70vh]">
          {renderView()}
        </main>

        <AIChat />
        <Footer onNavigate={(view) => setCurrentView(view)} />
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Waves, Bell, LayoutGrid, Globe, Zap, BarChart3, MessageSquare, ShieldAlert, Newspaper, Users, Home, Info, Mail, ShieldCheck, PenSquare } from 'lucide-react';
import { NOTIFICATIONS } from '../constants';
import { AppView } from '../App';

interface NavbarProps {
  onNavigate: (view: AppView) => void;
  currentView: AppView;
}

const Navbar: React.FC<NavbarProps> = ({ onNavigate, currentView }) => {
  const [showDepartments, setShowDepartments] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);

  const departments: { title: string; icon: any; view: AppView; anchor?: string }[] = [
    { title: 'أخبار السايبر', icon: Newspaper, view: 'home', anchor: 'news' },
    { title: 'تهديدات وتحذيرات', icon: ShieldAlert, view: 'home', anchor: 'threats' },
    { title: 'قصص دجلة', icon: Zap, view: 'home', anchor: 'stories' },
    { title: 'منصة الخبراء', icon: Users, view: 'experts' },
    { title: 'تحليلات وتقارير', icon: BarChart3, view: 'home', anchor: 'news' },
    { title: 'لوحة التحكم', icon: PenSquare, view: 'dashboard' },
    { title: 'من نحن', icon: Info, view: 'about' },
    { title: 'تواصل معنا', icon: Mail, view: 'contact' },
  ];

  const handleDeptClick = (dept: typeof departments[0]) => {
    onNavigate(dept.view);
    setShowDepartments(false);
    if (dept.anchor && dept.view === 'home') {
      setTimeout(() => {
        const element = document.getElementById(dept.anchor!);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
      }, 100);
    }
  };

  return (
    <nav className="sticky top-0 z-50 bg-slate-950/80 backdrop-blur-xl border-b border-cyan-500/10 transition-colors duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">

          {/* Logo */}
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => onNavigate('home')}>
            <div className="relative">
              <div className="absolute inset-0 bg-cyan-400/20 blur-xl rounded-full group-hover:bg-cyan-400/40 transition-all"></div>
              <Waves className="w-10 h-10 text-cyan-400 relative z-10" />
            </div>
            <span className="text-2xl font-black tracking-tighter text-white italic">دجلة<span className="text-cyan-400">سايبر</span></span>
          </div>

          {/* Nav Links */}
          <div className="hidden md:flex items-center gap-6 lg:gap-8">
            <button 
              onClick={() => onNavigate('home')} 
              className={`text-sm font-black transition-all flex items-center gap-2 px-3 py-1.5 rounded-lg ${currentView === 'home' ? 'text-cyan-400 bg-cyan-500/5 shadow-[0_0_15px_rgba(6,182,212,0.1)]' : 'text-slate-300 hover:text-cyan-400'}`}
            >
              <Home className="w-4 h-4" />
              الرئيسية
            </button>

            <button 
              onClick={() => onNavigate('dashboard')} 
              className={`flex items-center gap-2 text-sm font-black transition-all px-3 py-1.5 rounded-lg ${currentView === 'dashboard' ? 'text-cyan-400 bg-cyan-500/5 shadow-[0_0_15px_rgba(6,182,212,0.1)]' : 'text-slate-300 hover:text-cyan-400'}`}
            >
              <PenSquare className="w-4 h-4" />
              مركز النشر
            </button>

            {/* All Sections Mega Icon */}
            <div className="relative">
              <button 
                onClick={() => setShowDepartments(!showDepartments)}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all border ${showDepartments ? 'bg-cyan-600 border-cyan-500 text-white shadow-2xl shadow-cyan-900/40' : 'bg-slate-900 border-slate-800 text-slate-400 hover:text-cyan-400 hover:border-cyan-500/30'}`}
              >
                <LayoutGrid className="w-4 h-4" />
                <span className="text-xs font-black uppercase tracking-widest">كافة الأقسام</span>
              </button>

              {showDepartments && (
                <>
                  <div className="fixed inset-0 z-[-1]" onClick={() => setShowDepartments(false)}></div>
                  <div className="absolute left-0 mt-4 w-72 bg-slate-900/95 backdrop-blur-2xl border border-slate-800 shadow-[0_0_50px_rgba(0,0,0,0.5)] rounded-2xl overflow-hidden animate-fade-in p-2 text-right">
                    <div className="p-3 mb-2 border-b border-slate-800 text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">The Intelligence Grid</div>
